using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private ITransformer _model = null!;
    private PredictionEngine<TicketData, TicketPrediction> _predictionEngine = null!;
    private readonly string _dataPath;
    private string[] _categoryNames = [];

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = dataPath;
    }

    /// <summary>
    /// Trains the model and returns cross-validated evaluation metrics.
    /// </summary>
    public EvaluationResult TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine Subject + Description into a single text feature,
        // then featurize text and include Priority.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Cross-validate with the small dataset (leave-one-out style, k = number of rows)
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 5);

        // Train final model on all data
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract label names from the trained model's key-to-value mapping
        var schema = _model.GetOutputSchema(dataView.Schema);
        var labelColumn = schema.GetColumnOrNull("Label");
        if (labelColumn.HasValue)
        {
            var keyType = labelColumn.Value.Type as KeyDataViewType;
            if (keyType != null)
            {
                VBuffer<ReadOnlyMemory<char>> keys = default;
                schema[labelColumn.Value.Name].GetKeyValues(ref keys);
                _categoryNames = keys.DenseValues()
                    .Select(v => v.ToString()).ToArray();
            }
        }

        // Aggregate cross-validation metrics
        var avgMetrics = new EvaluationResult
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
        };

        // Per-category precision/recall from the best fold
        var bestFold = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
        var cm = bestFold.Metrics.ConfusionMatrix;

        for (var i = 0; i < cm.PerClassPrecision.Count; i++)
        {
            avgMetrics.PerCategory.Add(new CategoryMetric
            {
                Category = i < _categoryNames.Length ? _categoryNames[i] : $"Class{i}",
                Precision = cm.PerClassPrecision[i],
                Recall = cm.PerClassRecall[i],
            });
        }

        return avgMetrics;
    }

    public PredictionResult Predict(TicketRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException(
                "Model has not been trained. Call POST /api/tickets/train first.");

        var prediction = _predictionEngine.Predict(new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        });

        var result = new PredictionResult
        {
            PredictedCategory = prediction.Category,
        };

        // Map confidence scores to category names
        for (var i = 0; i < prediction.Score.Length; i++)
        {
            var name = i < _categoryNames.Length ? _categoryNames[i] : $"Class{i}";
            result.Confidence[name] = prediction.Score[i];
        }

        return result;
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Trains the ML model on the CSV data and returns evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResult> Train()
    {
        var metrics = _classifier.TrainAndEvaluate();
        return Ok(metrics);
    }

    /// <summary>
    /// Predicts the category for a new support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<PredictionResult> Predict([FromBody] TicketRequest request)
    {
        try
        {
            var result = _classifier.Predict(request);
            return Ok(result);
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }
}

