+            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
+        };
+
+        // Per-category precision/recall from the best fold
+        var bestFold = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
+        var cm = bestFold.Metrics.ConfusionMatrix;
+
+        for (var i = 0; i < cm.PerClassPrecision.Count; i++)
+        {
+            avgMetrics.PerCategory.Add(new CategoryMetric
+            {
+                Category = i < _categoryNames.Length ? _categoryNames[i] : $"Class{i}",
+                Precision = cm.PerClassPrecision[i],
+                Recall = cm.PerClassRecall[i],
+            });
+        }
+
+        return avgMetrics;
+    }
+
+    public PredictionResult Predict(TicketRequest request)
+    {
+        if (_predictionEngine is null)
+            throw new InvalidOperationException(
+                "Model has not been trained. Call POST /api/tickets/train first.");
+
+        var prediction = _predictionEngine.Predict(new TicketData
+        {
+            Subject = request.Subject,
+            Description = request.Description,
+            Priority = request.Priority,
+        });
+
+        var result = new PredictionResult
+        {
+            PredictedCategory = prediction.Category,
+        };
+
+        // Map confidence scores to category names
+        for (var i = 0; i < prediction.Score.Length; i++)
+        {
+            var name = i < _categoryNames.Length ? _categoryNames[i] : $"Class{i}";
+            result.Confidence[name] = prediction.Score[i];
+        }
+
+        return result;
+    }
+}
